// How algo was made
// The Passwords are generated by mixing two different algorithms Backtracking and DFS
// Here using the specified base words all the possible permutations are created with backtracking and DFS
// The idea to generate this came from the Leetcode problem #17 Letter Combination of a phone number

// Algo Working:
// The Algo processes the word letter by letter, building a tree of choice
// When it hits a letter that is not present in our leetMap > letter is added and algo keeps moving forward
// But when it hits a letter that is present in our leetMap > the algo branches

// Backtracking here explores the first branch all the way to end of word and saves the final result than backtrack to last branching point to explore next path
package main

import (
	"crypto/sha1"
	"encoding/hex"
	"fmt"
	"log"
	"os"
)

// Things to do to make it a bit fun > Expand leetMap
var leetMap = map[rune][]rune{
	'a': {'a', '@', '4'},
	'e': {'e', '3'},
	'i': {'i', '1', '!'},
	'o': {'o', '0'},
	's': {'s', '$', '5'},
}

func main() {
	baseWords := []string{"CSD356", "FoundationOfInformationSecurity", "SuryanshRohil", "Shiv Nadar University"}
	var dictionary []string

	for _, word := range baseWords {
		var variations []string

		// Generate all internal character variations using backtracking
		generateLeetCombinations(word, 0, "", &variations)

		// Custom Suffix Padding Layer
		// For every variation, append a symbol and a year (e.g., 2024 to 2026)
		symbols := []string{"!", "@", "#"}
		for _, v := range variations {
			// Add the raw variation first
			dictionary = append(dictionary, v)

			// Add padded variations
			for _, sym := range symbols {
				for year := 2024; year <= 2026; year++ {
					customPass := fmt.Sprintf("%s%s%d", v, sym, year)
					dictionary = append(dictionary, customPass)
				}
			}
		}
	}

	// Save Dictionary to file
	dictFile, err := os.Create("dictionary.txt")
	if err != nil {
		log.Fatalf("Failed to create dictionary file: %v", err)
	}
	defer dictFile.Close()

	for _, pass := range dictionary {
		dictFile.WriteString(pass + "\n")
	}
	fmt.Printf("Generated %d custom passwords and saved to dictionary.txt\n", len(dictionary))

	// Compute SHA
	// Save fiel
	hashFile, err := os.Create("hashes.txt")
	if err != nil {
		log.Fatalf("Failed to create hashes file: %v", err)
	}
	defer hashFile.Close()

	for _, pass := range dictionary {
		hasher := sha1.New()
		hasher.Write([]byte(pass))
		hashString := hex.EncodeToString(hasher.Sum(nil))
		hashFile.WriteString(hashString + "\n")
	}
	fmt.Println("Computed SHA-1 hashes and saved to hashes.txt")
}

// generateLeetCombinations uses Backtracking to branch out and build strings.
func generateLeetCombinations(word string, index int, current string, results *[]string) {
	// Base case: If we've processed all letters, add the built word to our results
	if index == len(word) {
		*results = append(*results, current)
		return
	}

	char := rune(word[index])

	// If the current character is in our substitution map, branch out
	if substitutions, exists := leetMap[char]; exists {
		for _, subChar := range substitutions {
			// Recursive call: branch for each possible substitution
			generateLeetCombinations(word, index+1, current+string(subChar), results)
		}
	} else {
		// If no substitution exists, just keep the character and move forward
		generateLeetCombinations(word, index+1, current+string(char), results)
	}
}
